     1→/**
     2→ * Classification Pipeline Orchestrator
     3→ *
     4→ * Orchestrates the complete 9-stage classification pipeline with canonical signatures:
     5→ * (email, session, result, config) => void
     6→ *
     7→ * Pipeline Stages:
     8→ * 1. Hard Assertions - Domain-based high-confidence categorization
     9→ * 2. Strong Indicators - Weighted seed scoring with diminishing returns
    10→ * 3. Rule Scoring - Hierarchical pattern matching (high/medium/low tiers)
    11→ * 4. Attribute Detection - Cross-cutting signals (urgency, domains, structural patterns)
    12→ * 5. Attribute Influence - Role-based bonuses (CORE, PRIMARY_BOOST, etc.)
    13→ * 6. Disambiguation - Pairwise conflict resolution for close scores
    14→ * 7. Multi-label Selection - Confidence-based label assignment with co-presence rules
    15→ * 8. AI Routing - Selective AI classification for uncertain cases
    16→ * 9. Final Decision - Label assignment and action determination
    17→ * 10. Audit Trail - Complete explainability trace generation
    18→ */
    19→
    20→import { EmailMessage } from '../types/email-message';
    21→import { CategoryConfiguration } from '../types/category-configuration';
    22→import { ClassificationResult } from '../types/classification-result';
    23→import { ClassificationSession } from '../types/classification-session';
    24→
    25→// Validation utilities
    26→import { validateEmailInput, validateConfigInput } from '../utils/validation';
    27→
    28→// Domain lookup loader
    29→import { loadDomainLookup, DomainLookup } from '../config/domain-resolver';
    30→
    31→// Initialization utilities
    32→import {
    33→  createClassificationSession,
    34→  createClassificationResult,
    35→  incrementSessionSuccess,
    36→  incrementSessionError,
    37→  finalizeClassificationSession,
    38→} from '../utils/initialization';
    39→
    40→// Pipeline stages (canonical signatures)
    41→import { executeHardAssertions } from '../stages/hard-assertions';
    42→import { executeStrongIndicators } from '../stages/strong-indicators';
    43→import { executeRuleScoring } from '../stages/rule-scoring';
    44→import { executeAttributeDetection } from '../stages/attribute-detection';
    45→import { executeAttributeInfluence } from '../stages/attribute-influence';
    46→import { executeDisambiguation } from '../stages/disambiguation';
    47→import { executeMultiLabelSelection } from '../stages/multi-label-selection';
    48→import { aiRoutingStage } from '../stages/ai-routing';
    49→import { aiFeatureExtractionStage } from '../stages/ai-feature-extraction';
    50→import { aiClassificationStage } from '../stages/ai-classification';
    51→import { aiLabelFilteringStage } from '../stages/ai-label-filtering';
    52→import { actionDeterminationStage } from '../stages/action-determination';
    53→// import { generateAuditTrail } from '../stages/audit-trail'; // TODO PENDING (T036): Wire audit trail after PipelineResults refactoring (deferred to T052)
    54→
    55→// Stage-specific config types
    56→import type { HardAssertionStageConfig } from '../stages/hard-assertions';
    57→import type { StrongIndicatorStageConfig } from '../stages/strong-indicators';
    58→import type { RuleScoringStageConfig } from '../stages/rule-scoring';
    59→import type { AttributeDetectionStageConfig } from '../stages/attribute-detection';
    60→import type { MultiLabelConfig, ConfidenceThresholds } from '../stages/types';
    61→import type { AIRoutingConfig } from '../stages/ai-routing';
    62→import type { AIFeatureExtractionConfig } from '../stages/ai-feature-extraction';
    63→import type { AIClassificationConfig } from '../stages/ai-classification';
    64→import type { AILabelFilteringConfig } from '../stages/ai-label-filtering';
    65→import type { ActionDeterminationConfig } from '../stages/action-determination';
    66→// import type { AuditTrailConfig } from '../stages/audit-trail'; // TODO PENDING (T036): Wire audit trail after PipelineResults refactoring (deferred to T052)
    67→
    68→/**
    69→ * Pipeline stage execution order for replay functionality
    70→ */
    71→const STAGE_ORDER = [
    72→  'hard-assertions',
    73→  'strong-indicators',
    74→  'rule-scoring',
    75→  'attribute-detection',
    76→  'attribute-influence',
    77→  'disambiguation',
    78→  'multi-label-selection',
    79→  'ai-routing',
    80→  'ai-feature-extraction',
    81→  'ai-classification',
    82→  'ai-label-filtering',
    83→  'action-determination',
    84→] as const;
    85→
    86→/**
    87→ * Stage task interface for replay-from-stage support
    88→ *
    89→ * Wraps individual pipeline stage functions to enable selective execution
    90→ * based on replay parameters while maintaining minimal disruption to existing code.
    91→ */
    92→interface StageTask {
    93→  /**
    94→   * Stage identifier for replay functionality
    95→   */
    96→  name: string;
    97→
    98→  /**
    99→   * Execute the stage with canonical signature pattern
   100→   *
   101→   * @param email - Email message to process
   102→   * @param session - Classification session context
   103→   * @param result - Mutable classification result (modified in place)
   104→   * @param config - Stage-specific configuration
   105→   */
   106→  execute(
   107→    email: EmailMessage,
   108→    session: ClassificationSession,
   109→    result: ClassificationResult,
   110→    config: CategoryConfiguration
   111→  ): Promise<void>;
   112→
   113→  /**
   114→   * Determine if this stage should be skipped for replay functionality
   115→   *
   116→   * @param replayFromStage - Optional stage to start replay from
   117→   * @returns true if stage should be skipped, false to execute
   118→   */
   119→  shouldSkip(replayFromStage?: string): boolean;
   120→}
   121→
   122→/**
   123→ * Error result for batch processing when individual email fails
   124→ */
   125→export interface ClassificationErrorResult {
   126→  error: Error;
   127→  emailId: string;
   128→  processingDurationMs: number;
   129→}
   130→
   131→/**
   132→ * Classification Pipeline orchestrator
   133→ *
   134→ * Manages sequential execution of classification stages with proper context
   135→ * propagation, error handling, and performance tracking.
   136→ */
   137→export class ClassificationPipeline {
   138→  private readonly config: CategoryConfiguration;
   139→  private readonly testMode: boolean;
   140→  private readonly domainLookup: DomainLookup;
   141→
   142→  /**
   143→   * Initialize classification pipeline with validated configuration
   144→   *
   145→   * @param config - Complete category configuration including processingConfig
   146→   * @param testMode - If true, use timestamp-based session IDs for easier debugging
   147→   * @throws {Error} If configuration validation fails
   148→   */
   149→  constructor(config: CategoryConfiguration, testMode: boolean = false) {
   150→    // Validate processing configuration
   151→    validateConfigInput(config.processingConfig);
   152→
   153→    // Validate confidence thresholds specifically
   154→    const { confidenceThresholds } = config.processingConfig;
   155→    if (
   156→      !confidenceThresholds ||
   157→      confidenceThresholds.highConfidence < 0 ||
   158→      confidenceThresholds.mediumConfidence < 0 ||
   159→      confidenceThresholds.lowConfidence < 0 ||
   160→      confidenceThresholds.secondaryLabelMinGap < 0
   161→    ) {
   162→      throw new Error('Invalid confidence thresholds: all values must be non-negative');
   163→    }
   164→
   165→    this.config = config;
   166→    this.testMode = testMode;
   167→
   168→    // Load domain lookup from config/domain-sources.json
   169→    // Gracefully handles missing/malformed files by returning empty lookup
   170→    this.domainLookup = loadDomainLookup();
   171→  }
   172→
   173→  /**
   174→   * Get configuration (for testing and future stage integration)
   175→   */
   176→  getConfig(): CategoryConfiguration {
   177→    return this.config;
   178→  }
   179→
   180→  /**
   181→   * Helper function to determine if a stage should be skipped for replay
   182→   *
   183→   * @param stageName - Name of the current stage
   184→   * @param replayFromStage - Stage to start replay from (optional)
   185→   * @returns true if stage should be skipped, false to execute
   186→   */
   187→  private shouldSkipStage(stageName: string, replayFromStage?: string): boolean {
   188→    if (!replayFromStage) return false;
   189→    const replayIndex = STAGE_ORDER.indexOf(replayFromStage as (typeof STAGE_ORDER)[number]);
   190→    const currentIndex = STAGE_ORDER.indexOf(stageName as (typeof STAGE_ORDER)[number]);
   191→    return replayIndex !== -1 && currentIndex < replayIndex;
   192→  }
   193→
   194→  /**
   195→   * Stage configuration mapping for factory pattern
   196→   */
   197→  private readonly stageConfigs = {
   198→    'hard-assertions': () => this.getHardAssertionConfig(),
   199→    'strong-indicators': () => this.getStrongIndicatorConfig(),
   200→    'rule-scoring': () => this.getRuleScoringConfig(),
   201→    'attribute-detection': () => this.getAttributeDetectionConfig(),
   202→    'attribute-influence': () => this.config,
   203→    disambiguation: () => this.config,
   204→    'multi-label-selection': () => ({
   205→      multiLabel: this.getMultiLabelConfig(),
   206→      confidenceThresholds: this.getConfidenceThresholds(),
   207→    }),
   208→    'ai-routing': () => this.getAIRoutingConfig(),
   209→    'ai-feature-extraction': () => this.getAIFeatureExtractionConfig(),
   210→    'ai-classification': () => this.getAIClassificationConfig(),
   211→    'ai-label-filtering': () => this.getAILabelFilteringConfig(),
   212→    'action-determination': () => this.getActionDeterminationConfig(),
   213→  } as const;
   214→
   215→  /**
   216→   * Stage function mapping for factory pattern
   217→   */
   218→  private readonly stageFunctions = {
   219→    'hard-assertions': executeHardAssertions,
   220→    'strong-indicators': executeStrongIndicators,
   221→    'rule-scoring': executeRuleScoring,
   222→    'attribute-detection': executeAttributeDetection,
   223→    'attribute-influence': executeAttributeInfluence,
   224→    disambiguation: executeDisambiguation,
   225→    'multi-label-selection': (
   226→      email: EmailMessage,
   227→      session: ClassificationSession,
   228→      result: ClassificationResult,
   229→      config: { multiLabel: MultiLabelConfig; confidenceThresholds: ConfidenceThresholds }
   230→    ) => {
   231→      executeMultiLabelSelection(email, session, result, config.multiLabel, config.confidenceThresholds);
   232→    },
   233→    'ai-routing': aiRoutingStage,
   234→    'ai-feature-extraction': aiFeatureExtractionStage,
   235→    'ai-classification': aiClassificationStage,
   236→    'ai-label-filtering': aiLabelFilteringStage,
   237→    'action-determination': actionDeterminationStage,
   238→  } as const;
   239→
   240→  /**
   241→   * Conditional execution for AI stages
   242→   */
   243→  private readonly conditionalStages = new Set(['ai-feature-extraction', 'ai-classification', 'ai-label-filtering']);
   244→
   245→  /**
   246→   * Create a single stage task using factory pattern
   247→   */
   248→  private createStageTask(stageName: keyof typeof this.stageConfigs): StageTask {
   249→    return {
   250→      name: stageName,
   251→      execute: async (email, session, result, _config) => {
   252→        // Check if this is a conditional AI stage
   253→        if (this.conditionalStages.has(stageName) && !result.needsAiClassification) {
   254→          return;
   255→        }
   256→
   257→        const stageConfig = this.stageConfigs[stageName]();
   258→        const stageFunction = this.stageFunctions[stageName];
   259→        await stageFunction(email, session, result, stageConfig as never);
   260→      },
   261→      shouldSkip: (replayFromStage) => this.shouldSkipStage(stageName, replayFromStage),
   262→    };
   263→  }
   264→
   265→  /**
   266→   * Create ordered array of stage tasks using factory pattern
   267→   *
   268→   * Each stage task wraps existing stage functions with replay logic
   269→   * while preserving canonical signatures and conditional execution.
   270→   *
   271→   * @returns Array of stage tasks in execution order
   272→   */
   273→  private createStageTasks(): StageTask[] {
   274→    return STAGE_ORDER.map((stageName) => this.createStageTask(stageName));
   275→  }
   276→
   277→  /**
   278→   * Core pipeline execution logic shared by both classify methods
   279→   */
   280→  private async executePipelineStages(
   281→    email: EmailMessage,
   282→    session: ClassificationSession,
   283→    result: ClassificationResult,
   284→    pipelineStartTime: number,
   285→    replayFromStage?: string
   286→  ): Promise<void> {
   287→    // Get stage tasks array
   288→    const stageTasks = this.createStageTasks();
   289→
   290→    // Execute stages using StageTask architecture
   291→    for (const stageTask of stageTasks) {
   292→      // Check if this stage should be skipped for replay
   293→      if (stageTask.shouldSkip(replayFromStage)) {
   294→        if (this.testMode && replayFromStage) {
   295→          console.log(`Skipping stage: ${stageTask.name} (replay from: ${replayFromStage})`);
   296→        }
   297→        continue;
   298→      }
   299→
   300→      // Log stage execution only in test mode
   301→      if (this.testMode) {
   302→        console.log(`Executing stage: ${stageTask.name}`);
   303→      }
   304→
   305→      // Execute the stage with unified error handling
   306→      try {
   307→        await stageTask.execute(email, session, result, this.config);
   308→      } catch (error) {
   309→        throw new Error(`Stage '${stageTask.name}' failed: ${error instanceof Error ? error.message : String(error)}`);
   310→      }
   311→    }
   312→  }
   313→
   314→  /**
   315→   * Unified error handling for pipeline failures
   316→   */
   317→  private createPipelineError(email: EmailMessage, startTime: number, error: unknown): Error {
   318→    const endTime = Date.now();
   319→    const message = error instanceof Error ? error.message : String(error);
   320→    return new Error(`Classification pipeline failed for email ${email.id} after ${endTime - startTime}ms: ${message}`);
   321→  }
   322→
   323→  /**
   324→   * Execute classification pipeline using StageTask architecture with optional replay support
   325→   *
   326→   * Provides the foundation for true replay-from-stage functionality by iterating
   327→   * through stage tasks and selectively skipping stages based on replay parameters.
   328→   *
   329→   * @param email - Email message to classify
   330→   * @param replayFromStage - Optional stage name to start replay from
   331→   * @returns Complete classification result with selected labels
   332→   * @throws {Error} If email validation fails or any stage throws unrecoverable error
   333→   */
   334→  async classifyWithStageTask(email: EmailMessage, replayFromStage?: string): Promise<ClassificationResult> {
   335→    const pipelineStartTime = Date.now();
   336→
   337→    try {
   338→      // Validate email input
   339→      validateEmailInput(email);
   340→
   341→      // Create classification session for single email
   342→      const session = createClassificationSession(this.config.processingConfig, 'sequential', 1, this.testMode);
   343→
   344→      // Create classification result
   345→      const result = createClassificationResult(email.id, session.id, 0);
   346→
   347→      // Execute pipeline stages using shared logic
   348→      await this.executePipelineStages(email, session, result, pipelineStartTime, replayFromStage);
   349→
   350→      // Mark session as successful
   351→      incrementSessionSuccess(session);
   352→      finalizeClassificationSession(session);
   353→
   354→      // Update final processing time
   355→      result.processingDurationMs = Date.now() - pipelineStartTime;
   356→      result.processedAt = new Date();
   357→
   358→      return result;
   359→    } catch (error) {
   360→      throw this.createPipelineError(email, pipelineStartTime, error);
   361→    }
   362→  }
   363→
   364→  /**
   365→   * Execute classification pipeline using provided session (for batch processing)
   366→   *
   367→   * Uses an externally-created session to enable multiple emails to share the same
   368→   * sessionId. This is essential for batch processing where all emails should be
   369→   * grouped under one session for traceability.
   370→   *
   371→   * @param email - Email message to classify
   372→   * @param session - Existing classification session to use
   373→   * @param batchPosition - Position of email in batch (for result metadata)
   374→   * @param replayFromStage - Optional stage name to start replay from
   375→   * @returns Complete classification result with selected labels
   376→   * @throws {Error} If email validation fails or any stage throws unrecoverable error
   377→   */
   378→  async classifyWithSession(
   379→    email: EmailMessage,
   380→    session: ClassificationSession,
   381→    batchPosition: number = 0,
   382→    replayFromStage?: string
   383→  ): Promise<ClassificationResult> {
   384→    const pipelineStartTime = Date.now();
   385→
   386→    try {
   387→      // Validate email input
   388→      validateEmailInput(email);
   389→
   390→      // Create classification result using provided session
   391→      const result = createClassificationResult(email.id, session.id, batchPosition);
   392→
   393→      // Execute pipeline stages using shared logic
   394→      await this.executePipelineStages(email, session, result, pipelineStartTime, replayFromStage);
   395→
   396→      // Update final processing time
   397→      result.processingDurationMs = Date.now() - pipelineStartTime;
   398→      result.processedAt = new Date();
   399→
   400→      return result;
   401→    } catch (error) {
   402→      throw this.createPipelineError(email, pipelineStartTime, error);
   403→    }
   404→  }
   405→
   406→  /**
   407→   * Shared configuration composition helpers
   408→   */
   409→  private getBaseStageConfig() {
   410→    return {
   411→      confidenceThresholds: this.config.processingConfig.confidenceThresholds,
   412→      // Type assertion: CategorySignals structure is compatible with stage-specific signal configs
   413→      categorySignals: this.config.processingConfig.categorySignals as Record<string, never>,
   414→      domainLookup: this.domainLookup,
   415→    };
   416→  }
   417→
   418→  private getOpenAIConfig(requiredFor: string) {
   419→    const openaiApiKey = process.env.OPENAI_API_KEY || '';
   420→    if (!openaiApiKey) {
   421→      throw new Error(`OPENAI_API_KEY environment variable is required for ${requiredFor}`);
   422→    }
   423→    return {
   424→      apiKey: openaiApiKey,
   425→      model: 'gpt-4o-mini',
   426→      temperature: 0.0,
   427→      responseFormat: 'json_schema' as const,
   428→    };
   429→  }
   430→
   431→  private getRetryPolicy() {
   432→    return {
   433→      maxRetries: 3,
   434→      backoffMs: 1000,
   435→    };
   436→  }
   437→
   438→  /**
   439→   * Extract configuration for hard assertions stage
   440→   */
   441→  private getHardAssertionConfig(): HardAssertionStageConfig {
   442→    return this.getBaseStageConfig();
   443→  }
   444→
   445→  /**
   446→   * Extract configuration for strong indicators stage
   447→   */
   448→  private getStrongIndicatorConfig(): StrongIndicatorStageConfig {
   449→    const settings = this.config.processingConfig.settings;
   450→    return {
   451→      ...this.getBaseStageConfig(),
   452→      strongIndicatorBaseWeight: settings.strongIndicators?.baseWeight ?? 10,
   453→      diminishingReturnsFactor: settings.strongIndicators?.diminishingReturnsFactor ?? 0.5,
   454→    };
   455→  }
   456→
   457→  /**
   458→   * Extract configuration for rule scoring stage
   459→   */
   460→  private getRuleScoringConfig(): RuleScoringStageConfig {
   461→    const tuningParams = this.config.processingConfig.settings.ruleScoring.tuningParameters;
   462→    return {
   463→      topLevelCategories: this.config.processingConfig.topLevelCategories,
   464→      settings: this.config.processingConfig.settings.ruleScoring,
   465→      tuningParameters: {
   466→        // Map config values (KHigh, KMedium, KLow) to internal names (K_high, K_medium, K_low)
   467→        // These represent tier weights in the rule scoring algorithm
   468→        K_high: tuningParams?.KHigh ?? 1,
   469→        K_medium: tuningParams?.KMedium ?? 0.7,
   470→        K_low: tuningParams?.KLow ?? 0.3,
   471→        // M_medium and M_low are multipliers for medium/low confidence rules
   472→        // Default to values that allow graceful degradation
   473→        M_medium: tuningParams?.KMedium ?? 0.7,
   474→        M_low: tuningParams?.KLow ?? 0.3,
   475→        // TAIL_DAMPEN and TAIL_RATIO_CAP control score aggregation behavior
   476→        // Use conservative defaults if not specified in config
   477→        TAIL_DAMPEN: 0.5,
   478→        TAIL_RATIO_CAP: 0.25,
   479→      },
   480→    };
   481→  }
   482→
   483→  /**
   484→   * Extract configuration for attribute detection stage
   485→   */
   486→  private getAttributeDetectionConfig(): AttributeDetectionStageConfig {
   487→    return {
   488→      attributes: this.config.processingConfig.attributes,
   489→      settings: {
   490→        attributeProcessing: this.config.processingConfig.settings.attributeProcessing,
   491→      },
   492→      performanceCache: {}, // Optional performance cache for domain lookups
   493→    };
   494→  }
   495→
   496→  /**
   497→   * Extract configuration for multi-label selection stage
   498→   */
   499→  private getMultiLabelConfig(): MultiLabelConfig {
   500→    return {
   501→      maxLabels: this.config.processingConfig.multiLabelPolicy.maxTopLevelLabels,
   502→      minSecondaryConfidence: this.config.processingConfig.multiLabelPolicy.minConfidenceForAdditional,
   503→      allowedCombinations: this.config.processingConfig.settings.multiLabelSelection.allowedCombinations,
   504→    };
   505→  }
   506→
   507→  /**
   508→   * Get confidence thresholds
   509→   */
   510→  private getConfidenceThresholds(): ConfidenceThresholds {
   511→    return this.config.processingConfig.confidenceThresholds;
   512→  }
   513→
   514→  /**
   515→   * Extract configuration for AI routing stage
   516→   */
   517→  private getAIRoutingConfig(): AIRoutingConfig {
   518→    return {
   519→      settings: {
   520→        aiRouting: this.config.processingConfig.settings.aiRouting,
   521→      },
   522→      confidenceThresholds: this.config.processingConfig.confidenceThresholds,
   523→    };
   524→  }
   525→
   526→  /**
   527→   * Extract configuration for AI feature extraction stage
   528→   */
   529→  private getAIFeatureExtractionConfig(): AIFeatureExtractionConfig {
   530→    return {
   531→      openai: this.getOpenAIConfig('AI feature extraction'),
   532→      prompts: this.config.processingConfig.aiPrompts.featureExtraction,
   533→      featureExtractionSchema: {
   534→        name: 'email_feature_extraction',
   535→        description: 'Extract semantic features from email content',
   536→        schema: this.config.processingConfig.featureExtractionSchema as unknown as Record<string, unknown>,
   537→        strict: true,
   538→      },
   539→      retryPolicy: this.getRetryPolicy(),
   540→    };
   541→  }
   542→
   543→  /**
   544→   * Extract configuration for AI classification stage
   545→   */
   546→  private getAIClassificationConfig(): AIClassificationConfig {
   547→    return {
   548→      openai: this.getOpenAIConfig('AI classification'),
   549→      prompts: this.config.processingConfig.aiPrompts.finalClassification,
   550→      classificationSchema: {
   551→        name: 'email_classification',
   552→        description: 'Classify email into categories',
   553→        schema: {
   554→          type: 'object',
   555→          properties: {
   556→            primaryCategory: { type: 'string' },
   557→            secondaryCategories: { type: 'array', items: { type: 'string' } },
   558→            confidence: { type: 'number' },
   559→            reasoning: { type: 'string' },
   560→          },
   561→          required: ['primaryCategory', 'secondaryCategories', 'confidence', 'reasoning'],
   562→          additionalProperties: false,
   563→        },
   564→        strict: true,
   565→      },
   566→      skipConditions: {
   567→        highConfidenceThreshold: this.config.processingConfig.settings.aiRouting.highConfidenceThreshold,
   568→        skipReasons: this.config.processingConfig.settings.aiRouting.skipAiConditions,
   569→      },
   570→      retryPolicy: this.getRetryPolicy(),
   571→    };
   572→  }
   573→
   574→  /**
   575→   * Extract configuration for AI label filtering stage
   576→   */
   577→  private getAILabelFilteringConfig(): AILabelFilteringConfig {
   578→    return {
   579→      labelAssignmentRules: {
   580→        maxLabels: this.config.processingConfig.multiLabelPolicy.maxTopLevelLabels,
   581→        minSecondaryConfidence: this.config.processingConfig.multiLabelPolicy.minConfidenceForAdditional,
   582→        allowedCombinations: [],
   583→      },
   584→    };
   585→  }
   586→
   587→  /**
   588→   * Extract configuration for action determination stage
   589→   */
   590→  private getActionDeterminationConfig(): ActionDeterminationConfig {
   591→    return {
   592→      archiveThresholds: {
   593→        lowImportance: 0.3,
   594→        mediumImportance: 0.5,
   595→        highImportance: 0.7,
   596→      },
   597→      defaultArchiveThreshold: 'mediumImportance',
   598→      actionSettings: {
   599→        archiveIfBelowThreshold: true,
   600→        markAsReadIfArchived: false,
   601→        applyCustomActions: false,
   602→      },
   603→    };
   604→  }
   605→
   606→  /**
   607→   * Execute classification pipeline on single email
   608→   *
   609→   * Uses the StageTask architecture for consistent pipeline execution.
